import math
from functools import reduce


class Solution:
    def subsequencePairCount(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        count = 0
        for mask in range(3 ** n):
            seq1 = []
            seq2 = []
            m = mask
            for i in range(n):
                d = m % 3
                m //= 3
                if d == 1:
                    seq1.append(nums[i])
                elif d == 2:
                    seq2.append(nums[i])
            if seq1 and seq2:
                g1 = reduce(math.gcd, seq1)
                g2 = reduce(math.gcd, seq2)
                if g1 == g2:
                    count += 1
        return count % MOD

