from math import gcd


class Solution:
    def subsequencePairCount(self, nums: List[int]) -> int:
        MOD = 10 ** 9 + 7
        dp = {(0, 0): 1}
        for num in nums:
            new_dp = dict(dp)
            for (g1, g2), cnt in dp.items():
                ng1 = num if g1 == 0 else gcd(g1, num)
                key1 = (ng1, g2)
                new_dp[key1] = (new_dp.get(key1, 0) + cnt) % MOD
                ng2 = num if g2 == 0 else gcd(g2, num)
                key2 = (g1, ng2)
                new_dp[key2] = (new_dp.get(key2, 0) + cnt) % MOD
            dp = new_dp
        total = 0
        for (g1, g2), cnt in dp.items():
            if g1 != 0 and g1 == g2:
                total = (total + cnt) % MOD
        return total

