var subsequencePairCount = function(nums) {
    const MOD = 1000000007;
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    let dp = new Map();
    dp.set('0,0', { g1: 0, g2: 0, cnt: 1 });
    for (const num of nums) {
        const newDp = new Map(dp);
        for (const [, entry] of dp) {
            const { g1, g2, cnt } = entry;
            const ng1 = g1 === 0 ? num : gcd(g1, num);
            const key1 = ng1 + ',' + g2;
            const cur1 = newDp.get(key1);
            newDp.set(key1, { g1: ng1, g2, cnt: ((cur1 ? cur1.cnt : 0) + cnt) % MOD });
            const ng2 = g2 === 0 ? num : gcd(g2, num);
            const key2 = g1 + ',' + ng2;
            const cur2 = newDp.get(key2);
            newDp.set(key2, { g1, g2: ng2, cnt: ((cur2 ? cur2.cnt : 0) + cnt) % MOD });
        }
        dp = newDp;
    }
    let total = 0;
    for (const [, entry] of dp) {
        if (entry.g1 !== 0 && entry.g1 === entry.g2) total = (total + entry.cnt) % MOD;
    }
    return total;
};
